firebase_rules:
{
  "rules": {
    "dp_dialog_controller": {
      // Allows the app to read UI settings, Info, and Keys
      ".read": true,

      // Locks down the main database (prevents modifying UI or info)
      ".write": false,

      "security": {
        "authorized_hwids": {
          // SPECIAL RULE 1: Allows the HTML panel to generate and revoke keys
          ".write": true,

          "$key": {
            "linked_devices": {
              "$hwid": {
                // Allows the Android app to link its hardware ID
                ".write": true
              }
            }
          }
        }
      }
    },

    "Resellers": {
      // SPECIAL RULE 2: Allows the HTML panel to verify passwords and deduct balances
      ".read": true,
      ".write": true
    }
  }
}
